10	} from '@/types/actions/SendEmailToAllActivePlayers';
11	
12	interface SendEmailToAllActivePlayersDeps {
13	    playerService: Pick<typeof playerService, 'getAll'>;
14	    sendEmail: SendEmailProxy;
15	}
16	
17	const defaultDeps: SendEmailToAllActivePlayersDeps = {
18	    playerService,
19	    sendEmail: sendEmailCore,
20	};
21	
22	/**
23	 * Normalises an email address by trimming whitespace and converting to lower case.
24	 *
25	 * Accepts `string`, `null`, or `undefined` and returns an empty string when the
26	 * input is not provided. This helper does not validate that the result is a
27	 * syntactically valid email address.
28	 *
29	 * @param email - The email address to normalise.
30	 * @returns The normalised email address, or an empty string when not provided.
31	 */
32	function normalizeEmail(email: string) {
33	    return email.trim().toLowerCase();
34	}
35	
36	/**
37	 * Sends one email to all active players with de-duplicated recipients.
38	 *
39	 * Active players are those without a `finished` timestamp.
40	 * Recipients are built from account and extra email addresses.
41	 *
42	 * @param data - Email content payload.
43	 * @param deps - Optional service and email dependencies.
44	 * @returns The number of unique recipients emailed.
45	 */
46	export async function sendEmailToAllActivePlayersCore(
47	    mailOptions: Omit<SendMailOptions, 'bcc'>,
48	    deps: SendEmailToAllActivePlayersDeps = defaultDeps,
49	): Promise<SendEmailToAllActivePlayersResult> {
50	    const players = await deps.playerService.getAll({ activeOnly: true });
51	
52	    const recipients = new Set<string>();
53	    for (const player of players) {
54	        if (player.accountEmail) {
55	            const normalizedEmail = normalizeEmail(player.accountEmail);
56	            recipients.add(normalizedEmail);
57	        }
58	
59	        for (const extraEmail of player.extraEmails) {
60	            if (extraEmail.verified) {
61	                const normalizedEmail = normalizeEmail(extraEmail.email);
62	                recipients.add(normalizedEmail);
63	            }
64	        }
65	    }
66	
67	    if (recipients.size === 0) {
68	        return { recipientCount: 0 };
69	    }
70	
71	    const sortedRecipients = Array.from(recipients).sort();
72	    await deps.sendEmail({
73	        ...mailOptions,
74	        bcc: sortedRecipients.join(','),
75	    });
76	    return { recipientCount: recipients.size };
77	}
