30	 * @param deps - Optional service and email dependencies.
31	 * @returns The number of unique recipients emailed.
32	 */
33	export async function sendEmailToAllActivePlayersCore(
34	    mailOptions: Omit<SendMailOptions, 'bcc'>,
35	    deps: SendEmailToAllActivePlayersDeps = defaultDeps,
36	): Promise<SendEmailToAllActivePlayersResult> {
37	    const players = await deps.playerService.getAll({ activeOnly: true });
38	
39	    const recipients = new Set<string>();
40	    for (const player of players) {
41	        if (player.accountEmail) {
42	            const normalizedEmail = normalizeEmail(player.accountEmail);
43	            recipients.add(normalizedEmail);
44	        }
45	
46	        for (const extraEmail of player.extraEmails) {
47	            if (extraEmail.verified) {
48	                const normalizedEmail = normalizeEmail(extraEmail.email);
49	                recipients.add(normalizedEmail);
50	            }
51	        }
52	    }
53	
54	    if (recipients.size === 0) {
55	        return { recipientCount: 0 };
56	    }
57	
58	    const sortedRecipients = Array.from(recipients).sort();
59	    await deps.sendEmail({
60	        ...mailOptions,
61	        bcc: sortedRecipients.join(','),
62	    });
63	    return { recipientCount: recipients.size };
64	}
